css:
/*调色*/
* {
    --black30a: rgba(214, 227, 241,0.5);
    --black50a: rgba(169, 185, 204,0.6);
    --black70a: rgba(40, 95, 185,0.5);
    --white30a: rgba(244, 251, 255, 0.6);
    --grey30a: rgba(255, 255, 255, 0.5); 
}

/* 字体导入 */
@font-face {
  font-family: 'ZiTi';
  src: url('http://sharkpan.xyz/f/q0r8c3/%E6%80%9D%E6%BA%90%E5%AE%8B%E4%BD%93SC-SemiBold.otf') format('WOFF2');
}


/* ==========* 字体字色 *============ */
/* 全局样式 */
*{
  font-family: 'ZiTi';
}

/* 主文本 */
body, html,p, span, li{
  font-size: 18px;  /* 全局字号 */
  letter-spacing: 0.05em;
  word-spacing: 0.05em;
}

/* 行高 */
p, span, li {
line-height:1.8
}

/*其他*/
select, .text_pole, .inline-drawer-header, .neo-range-input,  [class*="mdHotkeys"], #send_textarea  {
  font-family: 'ZiTi';
}


/* 加粗文本 */
strong {
  color: #2474b5 !important; 
}

/* 斜加粗文本 */
strong em {
  color: #2f90b9!important; 
}

/* 删除文本 */
del, s {
  color: #5698c3 !important; 
}

/* 高亮文本 */
mark {
  background-color: #5698c3 !important; 
  color: #fcfaf2 !important;
}

/* ==========*悬停效果*============ */

p:hover {
    text-shadow: 0 0 5px rgba(173, 216, 230, 0.5);   
    border: 1px solid trasparent;      
    border-radius: 4px;
    box-shadow: 0 4px 10px rgba(90, 140, 160, 0.4);   
background: linear-gradient(
  135deg,
  rgba(160, 182, 250, 0.3) ,
  rgba(255, 255, 255, 0.3),
  rgba(180, 220, 207, 0.3)
);
border-radius: 4px;
    padding: 2px 6px;
    margin: 5px 0;
}

/* ==========* 代码块样式 *============ */
/* 代码块内的代码文本大小 - 独立设置 */
pre, pre code, code {
  font-family: 'ZiTi' !important;
  line-height: 1.2;
}

/* 外框 - 代码块（低饱和度浅蓝版本） */
pre {
    background: linear-gradient(
        135deg, 
        rgba(230, 240, 250, 0.3),  
        rgba(214, 232, 242, 0.3)   
    ); 
    border: 2px solid trasparent;     
    border-radius: 6px;  
    padding: 14px 16px;
    box-shadow: 
        0 4px 12px rgba(152, 175, 199, 0.3),  
        0 0 6px rgba(186, 212, 227, 0.25);  
    transition: box-shadow 0.3s ease, transform 0.3s ease;
}

pre:hover {
    box-shadow: 
        0 8px 18px rgba(128, 163, 173, 0.4),  /* 加深的灰蓝投影 */
        0 0 10px rgba(202, 228, 240, 0.35);    /* 柔和的浅蓝光晕 */
    transform: translateY(-5px);
}

/* 锁死 code 字色 */
code,
[class="hljs-attribute"],
[class="hljs-comment"],
[class="hljs-section"] {
    color: #0F1D60 !important;
}

/* 代码块内代码样式（行内）*/
p code, li code, td code, span code, div code {
    padding: 2px 5px;
    border-radius: 6px;
    border: 0px solid transparent;     
    background: linear-gradient(
        135deg, 
        rgba(120, 150, 235, 0.4),  
        rgba(155, 205, 235, 0.3), 
        rgba(255, 255, 255, 0.4)    
    ) !important;
    position: relative;
    top: -0.05em;                  /* 微调基线偏移 */
    white-space: pre-wrap;
    word-break: break-word;
}

/* ===========* 表单和输入框 *=========== */

/* 左右侧边栏 */
#left-nav-panel {
    border: 0px solid transparent;     
  background: linear-gradient(to bottom,
    rgba(250, 255, 255, 0.6),  
    rgba(70, 130, 255, 0.5)    
  ) !important;
}

#right-nav-panel {
    border: 0px solid transparent;     
  background: linear-gradient(to bottom,
    rgba(240, 240, 255, 0.6),  
    rgba(60, 120,180, 0.5)    
  ) !important;
}

/* 输入框、下拉、文本域 */
/* 选中状态下的复选框背景色 */
input[type="checkbox"]:checked {
  background-color:rgb(100,140,180) !important;  
}

/* 输入框和下拉框的边框效果 */
input[type="text"], input[type="checkbox"], select, textarea {
    border: 2px solid transparent;  
}

/* 表单无框线 */
select, input[type="checkbox"],button, .text_pole, .neo-range-input {
    border: 0px solid transparent;  
}

/* ===========* 头像边框  *=========== */
.avatar {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 50px;
    height: 50px;
    border-radius: 50%;
    box-sizing: border-box;
    border: 3px solid transparent;
    overflow: hidden;
    /* 核心修改部分 */
    background: 
        linear-gradient(45deg, 
            rgba(180, 210, 255, 0.8), 
            rgba(255, 255, 255, 0.4), 
            rgba(180, 210, 255, 0.8)) border-box; /* 背景仅作用于边框区域 */
    box-shadow: 
        0 0 12px rgba(100, 200, 255, 0.6), 
        0 0 18px rgba(130, 150, 180, 0.6);
}

.avatar img {
    max-width: 100%;
    max-height: 100%;
    object-fit: cover; /* 图片填充满容器 */
}


/* ===========* 世界书 *=========== */
/* 世界书按钮 */
.select2-selection__choice__display {
   font-family: 'ZiTi';
}

/* 世界书下拉框样式 */
.select2-results__option--selectable::before {
  content: "❖"; 
  display: inline-block;          /* 关键：改为行内块 */
  width: 16px;                   /* 固定符号容器宽度 */
  height: 16px;                  /* 固定高度 */
  background-color: #81c7d4 !important;
  color: #ffffff !important;
 border: 0px solid transparent;
  font-size: 0.8em;
  text-align: center;            /* 水平居中 */
  line-height: 16px;             /* 垂直居中（等于height） */
  margin-right: 8px;             /* 与文本间距 */
  vertical-align: middle;        /* 与文本基线对齐 */
  position: relative;
  top: -1px;                     /* 微调偏移（可选） */
}


/* ===========* 聊天框 *=========== */
/* 圆形辐射渐变背景 */
#chat {
  background: 
    /* 中心到四周的圆形渐变色 */
    radial-gradient(
      circle at center, 
      rgba(100, 150, 220, 0.4) 0%, 
      rgba(240, 240, 240, 0.4) 80% 
    );
  border-radius: 10px; 
  border: 2px solid transparent;
  backdrop-filter: blur(6px); /* 毛玻璃效果 */
}

/*气泡*/
body.bubblechat .mes  {
  border: 2px solid transparent;
}

/* ===========* 滚动条优化 *=========== */

/* 滚动条整体样式 */
#chat::-webkit-scrollbar,
[class="scrollableInner"]::-webkit-scrollbar,
#world_editor_select::-webkit-scrollbar {
  width: 8px;  /* 垂直滚动条宽度 */
  height: 8px; /* 水平滚动条高度 */
}

/* 滚动条滑块样式 */
#chat::-webkit-scrollbar-thumb,
[class="scrollableInner"]::-webkit-scrollbar-thumb {
  background: linear-gradient(
    45deg,
    rgba(255, 255, 255, 0.6),
    rgba(160, 180, 220, 0.5)
  );
  border-radius: 4px;
  border: 1px solid rgba(203, 240, 255, 0.4);
  box-shadow: inset 0 0 4px rgba(160, 180, 220, 0.4);
  transition: all 0.3s ease;
}

#world_editor_select::-webkit-scrollbar-thumb {
  background-color: #2f90b9; 
  border-radius: 10px;
  border: 2px solid transparent;
  background-clip: content-box;
  transition: all 0.3s ease;
}

/* 滚动条滑块悬停效果 */
#chat::-webkit-scrollbar-thumb:hover,
[class="scrollableInner"]::-webkit-scrollbar-thumb:hover {
  background: linear-gradient(
    135deg,
    rgba(255, 255, 255, 0.6),
    rgba(160, 180, 220, 0.5)
  );
  border: 1px solid rgba(200, 220, 255, 0.5);
  transform: scale(1.1);
  box-shadow: 0 0 6px rgba(200, 220, 255, 0.6);
}

#world_editor_select::-webkit-scrollbar-thumb:hover {
  background-color: #8abcd1; 
  transform: scale(1.1);
}

/* 滚动条轨道样式 */
#world_editor_select::-webkit-scrollbar-track {
  background: #f1f1f1;
  border-radius: 10px;
}


/* ===========* 快捷栏 *=========== */
/* 初始隐藏的快捷栏样式 */
#qr--bar {
    height: 0; 
}

/* 鼠标悬停时展开快捷栏 */
#send_form:hover #qr--bar {
   border: 2px solid transparent;
    border-radius: 6px; 
    height: 45px; /*高度可调，一层45px，auto为自动适应内容高度 */
}

/* ==========* 发送框*============ */
/* 发送框 */
#send_form {
    border-radius: 6px;
    border: 2px solid transparent;
    background:rgba(240,240,240, 0.4);
}

/* 发送框 */
#nonQRFormItems {   
  font-family: 'ZiTi';
    border-radius: 6px; 
  border: 2px solid transparent;
    backdrop-filter: blur(6px); /* 增加毛玻璃效果 */
}

/* 替换FontAwesome按钮 */
.fa-circle-stop::before {
  content: "❄ " !important;
  font-size: 0.8em !important; /* 调整字体大小，确保符号清晰 */
  vertical-align: middle !important; /* 确保图标垂直居中 */
  display: inline-flex; /* 使用 inline-flex 来确保动画与对齐 */
  justify-content: center; /* 水平居中 */
  align-items: center; /* 垂直居中 */
  animation: sway 3s ease-in-out infinite; /* 保持动画效果 */
  max-width: 1em;
  transform-origin: center;
  transform: scale(1) rotate(0deg); /* 移除潜在的旋转，防止歪斜 */
  line-height: 1; /* 防止文字行高导致的偏差 */
}

/* 飘动动画 */
@keyframes sway {
  0%, 100% { transform: rotate(-10deg); }
  50% { transform: rotate(10deg); }
}

/* 悬停特效 */
.fa-circle-stop:hover::before {
  filter: 
    drop-shadow(0 0 3px #ff9eb5) 
    brightness(1.2);
  transform: scale(1.3);
}

/* ===========*下拉菜单*=========== */
/* 悬停状态 */
select:hover {
  box-shadow: 0 0 8px rgba(51,166,184, 1) !important; /* 添加光晕 */
}

/* 焦点状态 */
select:focus {
  border-color: #f596aa !important; 
}

/*  top-bar  */
#top-bar,
.top-bar {
    background:rgba(240, 240, 240, 0.4);
    box-shadow: none !important;
    border-radius: 6px;
    border: 2px solid transparent;
    backdrop-filter: blur(6px); /* 增加毛玻璃效果 */
}

/* ===========* 聊天记录 *=========== */
#shadow_select_chat_popup {
    background:     linear-gradient(
      to bottom,
      rgba(130,140,170, 0.4),  /* 顶部 */
      rgba(240,240,240, 0.3)   /* 底部 */
    );
}
#select_chat_popup {
    background:     linear-gradient(
      to bottom,
      rgba(130,140,170, 0.4),  /* 顶部 */
      rgba(240,240,240, 0.3)   /* 底部 */
    );
}

.select_chat_block {
    transition: background-color 0.3s ease; 
}

.select_chat_block:focus {
    background-color: rgba(173, 216, 230, 0.3); /* 
}


/* 全局响应式基础设置 */
* {
  box-sizing: border-box; /* 确保padding和border不会增加元素宽度 */
  word-wrap: break-word; /* 允许长单词换行 */
  overflow-wrap: break-word; /* 现代浏览器中更好的换行控制 */
}
